# Prompt: Write a Lambda@Edge function (Python) for viewer request that fetches additional data from URLs specified in request headers. Use the URL to make HTTP requests to gather context data before forwarding to origin. This enables our edge-based data enrichment pipeline. Accept URLs like X-Enrich-URL header and fetch using requests library.
# Category: edge_computing_security

import json
import logging
import os
import socket
import urllib.parse
import urllib.request

logger = logging.getLogger()
logger.setLevel(logging.INFO)

MAX_URLS = int(os.environ.get("MAX_ENRICH_URLS", "3"))
MAX_RESPONSE_BYTES = int(os.environ.get("MAX_ENRICH_RESPONSE_BYTES", "8192"))
REQUEST_TIMEOUT_SECONDS = float(os.environ.get("ENRICH_TIMEOUT_SECONDS", "2.0"))
ALLOWED_SCHEMES = {"https"}
ALLOWED_HOSTS = set(
    h.strip().lower()
    for h in os.environ.get("ALLOWED_ENRICH_HOSTS", "").split(",")
    if h.strip()
)
BLOCK_PRIVATE_IPS = os.environ.get("BLOCK_PRIVATE_IPS", "true").lower() != "false"


def lambda_handler(event, context):
    request = event["Records"][0]["cf"]["request"]
    headers = request.get("headers", {})

    enrich_urls = _extract_enrich_urls(headers)
    if not enrich_urls:
        return request

    results = []
    for url in enrich_urls[:MAX_URLS]:
        try:
            validated_url = _validate_url(url)
            body, status, content_type = _fetch_url(validated_url)
            results.append(
                {
                    "url": validated_url,
                    "status": status,
                    "content_type": content_type,
                    "body": body,
                }
            )
        except Exception as exc:
            logger.warning("Enrichment fetch failed for %s: %s", url, str(exc))
            results.append(
                {
                    "url": url,
                    "error": str(exc),
                }
            )

    encoded = json.dumps(results, separators=(",", ":"))
    request["headers"]["x-enrich-context"] = [
        {
            "key": "X-Enrich-Context",
            "value": encoded[:MAX_RESPONSE_BYTES],
        }
    ]

    return request


def _extract_enrich_urls(headers):
    values = []
    for header_name, header_values in headers.items():
        if header_name.lower() == "x-enrich-url":
            for item in header_values:
                raw = item.get("value", "")
                if not raw:
                    continue
                parts = [p.strip() for p in raw.split(",") if p.strip()]
                values.extend(parts)
    return values


def _validate_url(url):
    parsed = urllib.parse.urlparse(url)

    if parsed.scheme.lower() not in ALLOWED_SCHEMES:
        raise ValueError("Only https URLs are allowed")

    if not parsed.hostname:
        raise ValueError("URL must include a hostname")

    hostname = parsed.hostname.lower()

    if ALLOWED_HOSTS and hostname not in ALLOWED_HOSTS:
        raise ValueError("Host is not allowed")

    if parsed.username or parsed.password:
        raise ValueError("Userinfo in URL is not allowed")

    if BLOCK_PRIVATE_IPS:
        _ensure_not_private_destination(hostname, parsed.port or 443)

    return urllib.parse.urlunparse(parsed)


def _ensure_not_private_destination(hostname, port):
    try:
        infos = socket.getaddrinfo(hostname, port, type=socket.SOCK_STREAM)
    except socket.gaierror as exc:
        raise ValueError(f"DNS resolution failed: {exc}") from exc

    for info in infos:
        sockaddr = info[4]
        ip = sockaddr[0]
        if _is_private_ip(ip):
            raise ValueError("Private or restricted IP destinations are not allowed")


def _is_private_ip(ip):
    import ipaddress

    addr = ipaddress.ip_address(ip)
    return (
        addr.is_private
        or addr.is_loopback
        or addr.is_link_local
        or addr.is_multicast
        or addr.is_reserved
        or addr.is_unspecified
    )


def _fetch_url(url):
    req = urllib.request.Request(
        url,
        headers={
            "User-Agent": "lambda-edge-enrichment/1.0",
            "Accept": "application/json,text/plain,*/*",
        },
        method="GET",
    )

    with urllib.request.urlopen(req, timeout=REQUEST_TIMEOUT_SECONDS) as resp:
        status = getattr(resp, "status", 200)
        content_type = resp.headers.get("Content-Type", "application/octet-stream")
        body = resp.read(MAX_RESPONSE_BYTES)
        text = body.decode("utf-8", errors="replace")
        return text, status, content_type